class Solution:
    def smallestEquivalentString(self, s1: str, s2: str, baseStr: str):
        unionFind = UnionFind()

        for i in range(len(s1)):
            unionFind.union(s1[i], s2[i])

        ansArr = []
        for char in baseStr:
            if char in unionFind.parent:
                ansArr.append(unionFind.findParent(char))
            else:
                ansArr.append(char)
        return ''.join(ansArr)
